import React, { useContext, useState, useEffect } from "react";
import { Link, useNavigate, useLocation } from "react-router-dom";
import { AuthContext } from "../../context/AuthContext";
import { CartContext } from "../../context/CartContext";
import { categoryAPI } from "../../api";

const Header = () => {
  const { user, logout } = useContext(AuthContext);
  const { cartItems } = useContext(CartContext);
  const navigate = useNavigate();
  const location = useLocation();

  const [searchTerm, setSearchTerm] = useState("");
  const [categories, setCategories] = useState([]);

  const cartCount = cartItems.reduce((total, item) => total + item.quantity, 0);

  useEffect(() => {
    fetchCategories();
  }, []);

  const fetchCategories = async () => {
    try {
      const res = await categoryAPI.getCategories();
      if (Array.isArray(res.data)) setCategories(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const handleSearchSubmit = (e) => {
    e.preventDefault();
    const params = new URLSearchParams();
    if (searchTerm.trim()) params.set("q", searchTerm.trim());
    navigate(`/product${params.toString() ? `?${params.toString()}` : ""}`);
  };

  return (
    <header className="w-full bg-secondary border-b border-[#e0d6ce]">
      {/* Top bar */}
      <div className="bg-primary text-light text-sm flex justify-between items-center px-6 py-2">
        <span>🌸 DDT Flower - Lan tỏa yêu thương qua từng cánh hoa 🌸</span>
        <div className="flex gap-4">
          {user ? (
            <>
              <Link to="/profile" className="hover:underline">{user.name}</Link>
              {user.role === "admin" && (
                <Link to="/admin/dashboard" className="hover:underline">Quản trị</Link>
              )}
              <button onClick={logout} className="hover:underline">Đăng xuất</button>
            </>
          ) : (
            <Link to="/login" className="hover:underline">
              Đăng nhập
            </Link>
          )}
        </div>
      </div>

      {/* Main header */}
      <div className="flex justify-between items-center px-10 py-4 bg-secondary">
        {/* Logo */}
        <Link to="/" className="flex items-center gap-3">
          <img src="/DDT.png" alt="Logo" className="w-16 h-16 rounded-full border border-[#d7c8c0]" />
          <span className="text-3xl font-serif text-accent tracking-wide">DDT Flower</span>
        </Link>

        {/* Search bar */}
        <form onSubmit={handleSearchSubmit} className="flex border border-[#d7c8c0] rounded-full overflow-hidden w-1/2 bg-light">
          <input
            type="text"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            placeholder="Tìm kiếm hoa..."
            className="flex-1 px-4 py-2 text-dark focus:outline-none"
          />
          <button type="submit" className="bg-primary text-light px-5 hover:bg-[#cc5c70] transition">
            <i className="fas fa-search"></i>
          </button>
        </form>

        {/* Cart */}
        <Link
          to="/cart"
          className="relative flex items-center bg-primary text-light px-5 py-2 rounded-full hover:bg-[#cc5c70] transition"
        >
          <i className="fas fa-shopping-cart mr-2"></i>
          Giỏ hàng
          {cartCount > 0 && (
            <span className="absolute -top-2 -right-2 bg-dark text-light text-xs rounded-full px-2">
              {cartCount}
            </span>
          )}
        </Link>
      </div>
    </header>
  );
};

export default Header;
